    int rightSide[82];
    int M = 9*9 + 1;
    for (int k = 1; k < M; k++) {
        rightSide[k-1] = b * (int)pow(k, a) + c;
    }

    int myList[82];
    int sol = 0;
    for (int i = 0; i < M-1; i++) {
        int x = rightSide[i];
        if (x > 0 && x < 1e9 && x == b * (int)pow(s(x), a) + c) {
            myList[sol++] = x;
        }
    }

    qsort(myList, sol, sizeof(int), compare);
    printf("%d\n", sol);
    for (int i = 0; i < sol; i++) {
        printf("%d ", myList[i]);
    }

